import React from "react";
import { Form, Col, Button } from "react-bootstrap";
import { Link } from "react-router-dom";
import { createDeck } from "../../utils/api/index.js";

function CreateDeck({ decks }) {
    const rawIdArray = decks.map(item => item.id);
    const idArray = rawIdArray.sort((itemA, itemB) => itemB > itemA ? 1 : -1)
    const newDeckId = idArray[0] + 1;

    function handleCreateDeckBtn() {
      const textInput = document.getElementById('deckTitleInput').innerText;
      console.log(textInput)
    }

  return (
    <div>
      <Form>
        <Col>
          <h1>Create Deck</h1>
          <Form.Label className="mt-1">Name</Form.Label>
          <Form.Control
            className="mt-1"
            placeholder="Deck Name"
            type="text"
            id="deckTitleInput"
          ></Form.Control>
          <Form.Label className="mt-1">Description</Form.Label>
          <Form.Control
            className="mt-1"
            placeholder="Brief description of the deck"
            as="textarea"
          ></Form.Control>
          <Link to="/">
            <Button className="mt-2 mr-1" variant="secondary">
              Cancel
            </Button>
          </Link>
          <Link to={`/decks/${newDeckId}`}>
            <Button onClick={() => handleCreateDeckBtn()} className="mt-2 mr-1">Submit</Button>
          </Link>
        </Col>
      </Form>
    </div>
  );
}

export default CreateDeck;
